"""Persist evidence records as JSON plus same-name HTML previews."""
from __future__ import annotations

import html
import hashlib
import json
import os
import re
from datetime import datetime
from pathlib import Path

from weixin.core.main import JSONS_DIR
from weixin.db.models import EvidenceRecord


class SafeHtml(str):
    """Small marker for HTML snippets generated by this module."""


def save_record(record: EvidenceRecord, overwrite_json_path: str = ""):
    """Save one evidence record to JSON and generate a sibling HTML preview.

    If *overwrite_json_path* is given, overwrite that file instead of creating a new one.
    """
    os.makedirs(JSONS_DIR, exist_ok=True)

    ts = datetime.now().strftime("%Y%m%d_%H%M%S")
    data = record.to_dict()
    identifier = build_video_identifier(data)
    data.setdefault("candidate", {})["video_identifier"] = identifier

    if overwrite_json_path:
        path = overwrite_json_path
        keyword_slug = filename_slug(data.get("search_keyword", ""), fallback="keyword", max_len=14)
        blogger_slug = filename_slug(primary_blogger_name(data), fallback="blogger", max_len=14)
        # 仅用于日志显示
        _display = f"result_{ts}_{keyword_slug}_{blogger_slug}_{identifier}.json"
    else:
        keyword_slug = filename_slug(data.get("search_keyword", ""), fallback="keyword", max_len=14)
        blogger_slug = filename_slug(primary_blogger_name(data), fallback="blogger", max_len=14)
        path = os.path.join(JSONS_DIR, f"result_{ts}_{keyword_slug}_{blogger_slug}_{identifier}.json")
        _display = os.path.basename(path)

    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    html_path = os.path.splitext(path)[0] + ".html"
    with open(html_path, "w", encoding="utf-8") as f:
        f.write(render_record_html(data, json_path=path))

    # 只在首次写入时追加 results.jsonl
    if not overwrite_json_path:
        lpath = os.path.join(JSONS_DIR, "results.jsonl")
        with open(lpath, "a", encoding="utf-8") as f:
            f.write(json.dumps(data, ensure_ascii=False) + "\n")

    print(f"[store] saved json: {path}")
    print(f"[store] saved html: {html_path}")
    return path


def build_video_identifier(data: dict) -> str:
    candidate = data.get("candidate", {}) or {}
    video = data.get("video_info", {}) or {}
    profile = data.get("profile_info", {}) or {}
    traffic = data.get("traffic_info", {}) or {}
    screenshots = data.get("screenshots", []) or []
    play_hash = first_play_screenshot_hash(screenshots)
    parts = [
        data.get("search_keyword", ""),
        candidate.get("title_text", ""),
        candidate.get("hit_text", ""),
        video.get("blogger_name", ""),
        profile.get("name", ""),
        video.get("video_channel_id", ""),
        profile.get("account", ""),
        video.get("publish_time", ""),
        traffic.get("marker_text", ""),
        play_hash,
        candidate.get("fingerprint", ""),
    ]
    raw = "|".join(str(part or "") for part in parts)
    return hashlib.sha1(raw.encode("utf-8")).hexdigest()[:16]


def first_play_screenshot_hash(paths: list) -> str:
    for path in paths or []:
        if not Path(path).name.lower().startswith("play_"):
            continue
        try:
            data = Path(path).read_bytes()
        except OSError:
            continue
        return hashlib.sha1(data).hexdigest()
    return ""


def primary_blogger_name(data: dict) -> str:
    video = data.get("video_info", {}) or {}
    profile = data.get("profile_info", {}) or {}
    traffic = data.get("traffic_info", {}) or {}
    return first_non_empty(
        video.get("blogger_name"),
        profile.get("name"),
        traffic.get("target_blogger_name"),
    )


def filename_slug(value: str, fallback: str, max_len: int = 14) -> str:
    value = re.sub(r'[\\/:*?"<>|\\s]+', "_", str(value or "").strip())
    value = value.strip("._")
    if not value:
        value = fallback
    return value[:max_len]


def load_seen(path=None):
    """Load collected fingerprints for duplicate detection."""
    if path is None:
        path = os.path.join(JSONS_DIR, "results.jsonl")
    seen = set()
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                try:
                    d = json.loads(line)
                    fp = d.get("candidate", {}).get("fingerprint", "")
                    if fp:
                        seen.add(fp)
                except json.JSONDecodeError:
                    continue
    print(f"[store] loaded seen fingerprints: {len(seen)}")
    return seen


def clear_seen(path=None):
    """清空历史指纹记录，每次新任务开始时调用。"""
    if path is None:
        path = os.path.join(JSONS_DIR, "results.jsonl")
    if os.path.exists(path):
        os.remove(path)
        # 创建空文件，确保后续追加写入正常
        with open(path, "w", encoding="utf-8") as f:
            f.write("")
        print(f"[store] cleared seen fingerprints")


def render_record_html(data: dict, json_path: str = "") -> str:
    title = first_non_empty(
        data.get("video_info", {}).get("title"),
        data.get("candidate", {}).get("title_text"),
        data.get("candidate", {}).get("hit_text"),
        "Weixin evidence record",
    )
    subtitle = first_non_empty(
        data.get("video_info", {}).get("blogger_name"),
        data.get("profile_info", {}).get("name"),
        data.get("traffic_info", {}).get("target_blogger_name"),
    )
    media = data.get("media_info", {}) or {}
    screenshots = data.get("screenshots", []) or []
    json_href = file_uri(json_path) if json_path else ""
    video_path = media.get("recording_video_path", "") or ""

